const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
const text = binaryData.toString('utf-8');

return [{ json: { resume_text: text } }];

const data = $input.first().json;

const employmentMap = {
  "Полная занятость": "full",
  "Частичная занятость": "part",
  "Подработка": "probation",
  "Вахта": "volunteer",
  "Стажировка": "contractor"
};
const scheduleMap = {
  "На месте работодателя": "fullDay",
  "Удалённо": "remote",
  "Гибрид": "flexible",
  "Разъездной": "flyInFlyOut"
};
const searchFieldMap = {
  "В названии вакансии": "name",
  "В описании вакансии": "description",
  "В названии компании": "company_name"
};

const search_queries = data.search_queries.split("\n").filter(x => x.trim() !== "");
const exclude_words = data.exclude_words.split("\n").filter(x => x.trim() !== "");
const exclude_part = exclude_words.map(w => `NOT ${w}`).join(" ");
const text = search_queries.map(q => `(${q} ${exclude_part})`).join(" OR ");

const employment = data.employment.split(", ").map(x => employmentMap[x.trim()]).filter(Boolean);
const schedule = data.schedule.split(", ").map(x => scheduleMap[x.trim()]).filter(Boolean);
const search_field = data.search_field.split(", ").map(x => searchFieldMap[x.trim()]).filter(Boolean);

const parts = [];
parts.push(`text=${encodeURIComponent(text)}`);
parts.push(`per_page=100`);
parts.push(`only_with_salary=${data.only_with_salary === "Да"}`);

employment.forEach(v => parts.push(`employment=${v}`));
schedule.forEach(v => parts.push(`schedule=${v}`));
search_field.forEach(v => parts.push(`search_field=${v}`));

if (data.salary_min && data.salary_min !== "0") {
  parts.push(`salary=${data.salary_min}`);
}

return [{
  json: {
    chat_id: data.chat_id,
    url: `https://api.hh.ru/vacancies?${parts.join('&')}`
  }
}];

const items = $input.all();

// Функция парсинга даты DD.MM.YYYY HH:MM:SS
function parseRussianDate(dateStr) {
  const [datePart, timePart] = dateStr.split(' ');
  const [day, month, year] = datePart.split('.');
  const [hour, minute, second] = timePart.split(':');

  // Месяцы в JS начинаются с 0
  return new Date(year, month - 1, day, hour, minute, second);
}

// Сортируем по времени (новые первыми)
items.sort((a, b) => {
  const timeA = parseRussianDate(a.json['Отметка времени']);
  const timeB = parseRussianDate(b.json['Отметка времени']);
  return timeB - timeA; // descending
});

// Возвращаем только первый (самый новый)
return [items[0]];

